/**
 * @name LoggerRequestProcessor checkPathSecurity bypass - full taint flow from network command to file
 * @description Network commands bypass LoggerRequestProcessor.checkPathSecurity() via path not canonicalized before startsWith check
 * @kind path-problem
 * @problem.severity error
 * @id java/logger-checkpathsecurity-bypass
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module CheckPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Path from any of the log request command types
    exists(FieldAccess fa |
      fa.getField().getName() = "path" and
      fa.getField().getDeclaringType().getPackage().getName().matches("%command.log%") and
      source.asExpr() = fa
    )
    or
    exists(MethodCall mc |
      mc.getMethod().getName() = "getPath" and
      mc.getMethod().getDeclaringType().getPackage().getName().matches("%command.log%") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Any file read/access in LoggerRequestProcessor
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = cie.getArgument(0)
    )
    or
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "RandomAccessFile") and
      sink.asExpr() = cie.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("readFileToByteArray") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    exists(MethodCall mc |
      (mc.getMethod().hasName("tail") or mc.getMethod().hasName("readLines")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Treat validated path as barrier only if it goes through getCanonicalPath first
    exists(MethodCall mc |
      mc.getMethod().hasName("getCanonicalPath") and
      node.asExpr() = mc
    )
  }
}

module CheckPathFlow = TaintTracking::Global<CheckPathConfig>;
import CheckPathFlow::PathGraph

from CheckPathFlow::PathNode source, CheckPathFlow::PathNode sink
where CheckPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Log request path from $@ flows to file operation without canonicalization-based containment check.", source.getNode(), "log command path field"

/**
 * @name Zip/archive entry name path traversal (zip slip)
 * @description ZipEntry names flow to File constructors without validation - allows writing outside target directory
 * @kind path-problem
 * @problem.severity error
 * @id java/zip-slip
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = cie.getAnArgument()
    )
    or
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = cie.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Barrier if there's a check for ".." in the entry name
    exists(MethodCall mc |
      mc.getMethod().hasName("contains") and
      mc.getAnArgument().(StringLiteral).getValue() = ".." and
      DataFlow::localFlow(node, DataFlow::exprNode(mc.getQualifier()))
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Zip slip: ZipEntry name from $@ flows to file operation.", source.getNode(), "zip entry name"
